import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is the distance formula?", a: "The distance formula is d = sqrt((x2 - x1)^2 + (y2 - y1)^2). It finds the straight-line distance between two points on a coordinate plane." },
  { q: "How do you calculate the distance between two points?", a: "Subtract the x-coordinates and y-coordinates, square both differences, add them, then take the square root of the sum." },
  { q: "What is the midpoint formula?", a: "The midpoint formula is ((x1 + x2) / 2, (y1 + y2) / 2). It finds the point exactly halfway between two coordinates." },
  { q: "How do you find the slope between two points?", a: "Slope is (y2 - y1) / (x2 - x1). It measures the rise over run between the two points." },
  { q: "How is the distance formula related to the Pythagorean theorem?", a: "The horizontal and vertical differences form the legs of a right triangle. The distance between the points is the hypotenuse, so the formula comes directly from a^2 + b^2 = c^2." },
];

const fmt = (value: number) => Number.isFinite(value) ? Number(value.toFixed(4)).toLocaleString() : "Undefined";

export default function DistanceCalculator() {
  const [x1, setX1] = useState(1);
  const [y1, setY1] = useState(2);
  const [x2, setX2] = useState(4);
  const [y2, setY2] = useState(6);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  const result = useMemo(() => {
    const dx = x2 - x1;
    const dy = y2 - y1;
    const distance = Math.sqrt(dx * dx + dy * dy);
    const midpoint = `(${fmt((x1 + x2) / 2)}, ${fmt((y1 + y2) / 2)})`;
    const slope = dx === 0 ? "Undefined" : fmt(dy / dx);
    return { distance, midpoint, slope, step: `d = sqrt((${x2} - ${x1})^2 + (${y2} - ${y1})^2) = sqrt(${dx}^2 + ${dy}^2) = sqrt(${dx * dx + dy * dy}) = ${fmt(distance)}.` };
  }, [x1, y1, x2, y2]);

  return (
    <>
      <SEOHead title="Free Distance Calculator Online - Calculate Distance Between Two Points Instantly | CalcHive" description="Free online distance calculator. Calculate the distance between any two points using the distance formula with midpoint and slope included instantly. 100% free for students, no signup required." canonical="/distance-calculator" keywords="free distance calculator, distance between two points calculator free, distance formula calculator free online, coordinate distance calculator free, geometry distance calculator free" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Distance Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this distance between two points calculator free to calculate coordinate distance, midpoint, and slope instantly.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mb-8">
            <div><label htmlFor="x1" className="text-sm font-semibold text-foreground block mb-2">x1</label><input id="x1" type="number" inputMode="decimal" value={x1} onChange={(event) => setX1(Number(event.target.value))} className={inputClass} /></div>
            <div><label htmlFor="y1" className="text-sm font-semibold text-foreground block mb-2">y1</label><input id="y1" type="number" inputMode="decimal" value={y1} onChange={(event) => setY1(Number(event.target.value))} className={inputClass} /></div>
            <div><label htmlFor="x2" className="text-sm font-semibold text-foreground block mb-2">x2</label><input id="x2" type="number" inputMode="decimal" value={x2} onChange={(event) => setX2(Number(event.target.value))} className={inputClass} /></div>
            <div><label htmlFor="y2" className="text-sm font-semibold text-foreground block mb-2">y2</label><input id="y2" type="number" inputMode="decimal" value={y2} onChange={(event) => setY2(Number(event.target.value))} className={inputClass} /></div>
          </div>
          <motion.div key={`${x1}-${y1}-${x2}-${y2}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Distance</p><p className="text-6xl font-black text-white tracking-tight" data-testid="result-distance">{fmt(result.distance)}</p></div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground">Midpoint</p><p className="text-xl font-extrabold text-foreground">{result.midpoint}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground">Slope</p><p className="text-xl font-extrabold text-foreground">{result.slope}</p></div></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground font-mono" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Distance Between Two Points for Free</h2><p className="text-muted-foreground leading-relaxed">Enter two coordinate points and this distance formula calculator free online tool finds the straight-line distance instantly.</p>
          <h2 className="text-2xl font-bold text-foreground">How the Distance Formula Works in Geometry</h2><p className="text-muted-foreground leading-relaxed">The x and y differences form a right triangle, so the distance is found using the Pythagorean theorem.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Coordinate Distance Tool for Math Students</h2><p className="text-muted-foreground leading-relaxed">Use this coordinate distance calculator free for geometry homework, graphing, midpoint checks, and slope practice.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/distance-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


